import json

with open(locals()['var_function-call-5245459546365613242'], 'r') as f:
    paper_docs = json.load(f)

print("__RESULT__:")
for doc in paper_docs:
    if "ArmSleeve" in doc['filename']:
        idx = doc['text'].lower().find('physical activity')
        if idx != -1:
            print(json.dumps({
                "found": True, 
                "context": doc['text'][idx-50:idx+50]
            }))
        else:
            print(json.dumps({"found": False}))
